import React, { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { toast } from 'sonner'
import {
  CreditCard,
  CheckCircle,
  XCircle,
  Database,
  ArrowClockwise,
  Link,
  Lock
} from '@phosphor-icons/react'
import {
  getRazorpayConfig,
  saveRazorpayConfig,
  fetchRazorpayServerStatus,
  getCachedRazorpayServerStatus,
  type RazorpayConfig,
  type RazorpayServerStatus
} from '../../services/razorpayService'
import { cn } from '../../lib/utils'

export const RazorpaySettingsSection = () => {
  const [razorpayConfig, setRazorpayConfig] = useState<RazorpayConfig>(getRazorpayConfig())
  const [serverStatus, setServerStatus] = useState<RazorpayServerStatus | null>(getCachedRazorpayServerStatus())
  const [isRefreshing, setIsRefreshing] = useState(false)

  const refreshStatus = async () => {
    setIsRefreshing(true)
    try {
      const status = await fetchRazorpayServerStatus()
      setServerStatus(status)
      if (status.configured) {
        toast.success(status.message || 'Razorpay configured')
      } else {
        toast.error(status.message || 'Razorpay not configured on server')
      }
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Failed to check Razorpay status')
    } finally {
      setIsRefreshing(false)
    }
  }

  useEffect(() => {
    // Load server config status on mount (best-effort).
    void refreshStatus()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const isConfigured = Boolean(serverStatus?.configured)

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <CreditCard size={24} weight="duotone" className="text-blue-600" />
            Razorpay Payment Gateway
          </h2>
          <p className="text-sm text-muted-foreground mt-1">
            Razorpay keys are configured on the server (Firebase Functions). The app never stores secrets in the browser.
          </p>
        </div>

        {isConfigured ? (
          <div className="flex items-center gap-2 px-3 py-1.5 bg-green-100 text-green-700 rounded-full text-sm font-medium">
            <CheckCircle size={16} weight="fill" />
            Connected
          </div>
        ) : (
          <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-100 text-amber-800 rounded-full text-sm font-medium">
            <XCircle size={16} weight="fill" />
            Not Configured
          </div>
        )}
      </div>

      {!isConfigured && (
        <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 mb-6">
          <h3 className="font-semibold text-blue-800 mb-2">Server Setup</h3>
          <ol className="text-sm text-blue-700 space-y-2 list-decimal list-inside">
            <li>Set Firebase Functions secrets: `RAZORPAY_KEY_ID`, `RAZORPAY_KEY_SECRET`, `RAZORPAY_WEBHOOK_SECRET`</li>
            <li>Deploy functions</li>
            <li>Come back here and click Refresh Status</li>
          </ol>
        </div>
      )}

      <div className="space-y-6">
        <div className="bg-muted/30 rounded-xl p-5 border border-border">
          <h3 className="font-semibold mb-4 flex items-center gap-2">
            <Lock size={18} className="text-primary" />
            Server Configuration
          </h3>

          <div className="space-y-2 text-sm">
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Key ID</span>
              <span className="font-mono">{serverStatus?.keyId ? serverStatus.keyId : '-'}</span>
            </div>

            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Mode</span>
              <span
                className={cn(
                  'px-3 py-1 rounded-full text-xs font-medium',
                  serverStatus?.isLiveMode ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-800'
                )}
              >
                {serverStatus?.isLiveMode ? 'Live' : 'Test'}
              </span>
            </div>

            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Validation</span>
              <span className="text-xs">
                {serverStatus?.validated ? (
                  <span className="text-green-700 flex items-center gap-1">
                    <CheckCircle size={14} weight="fill" />
                    OK
                  </span>
                ) : (
                  <span className="text-muted-foreground flex items-center gap-1">
                    <Database size={14} />
                    Unknown
                  </span>
                )}
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2 pt-4">
            <button
              type="button"
              onClick={refreshStatus}
              disabled={isRefreshing}
              className="px-4 py-2.5 bg-muted text-foreground rounded-lg font-medium hover:bg-muted/80 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
              {isRefreshing ? (
                <>
                  <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                  Refreshing...
                </>
              ) : (
                <>
                  <ArrowClockwise size={18} />
                  Refresh Status
                </>
              )}
            </button>

            <a
              href="https://dashboard.razorpay.com"
              target="_blank"
              rel="noopener noreferrer"
              className="px-4 py-2.5 text-blue-600 hover:underline flex items-center gap-1 text-sm"
            >
              <Link size={16} />
              Open Razorpay Dashboard
            </a>
          </div>
        </div>

        <div className="bg-muted/30 rounded-xl p-5 border border-border">
          <h3 className="font-semibold mb-4">Enabled Payment Methods</h3>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            {[
              { key: 'upi', label: 'UPI' },
              { key: 'card', label: 'Card' },
              { key: 'netbanking', label: 'Net Banking' },
              { key: 'wallet', label: 'Wallet' }
            ].map(method => (
              <label
                key={method.key}
                className={cn(
                  'flex items-center gap-2 p-3 rounded-lg border cursor-pointer transition-all',
                  razorpayConfig.enabledMethods[method.key as keyof typeof razorpayConfig.enabledMethods]
                    ? 'bg-primary/10 border-primary'
                    : 'bg-background border-border hover:border-primary/50'
                )}
              >
                <input
                  type="checkbox"
                  checked={razorpayConfig.enabledMethods[method.key as keyof typeof razorpayConfig.enabledMethods]}
                  onChange={e =>
                    setRazorpayConfig(prev => ({
                      ...prev,
                      enabledMethods: { ...prev.enabledMethods, [method.key]: e.target.checked }
                    }))
                  }
                  className="sr-only"
                />
                <span className="font-medium text-sm">{method.label}</span>
              </label>
            ))}
          </div>
        </div>

        <div className="bg-muted/30 rounded-xl p-5 border border-border">
          <h3 className="font-semibold mb-4">Additional Options</h3>
          <div className="space-y-3">
            <label className="flex items-center justify-between cursor-pointer">
              <div>
                <span className="font-medium">Auto-generate Payment Links</span>
                <p className="text-sm text-muted-foreground">
                  Automatically create payment links when saving invoices
                </p>
              </div>
              <input
                type="checkbox"
                checked={razorpayConfig.autoGenerateLinks}
                onChange={e => setRazorpayConfig(prev => ({ ...prev, autoGenerateLinks: e.target.checked }))}
                className="w-5 h-5 rounded border-border text-primary focus:ring-primary"
              />
            </label>
          </div>
        </div>

        <div className="flex items-center gap-2 pt-2">
          <button
            type="button"
            onClick={() => {
              if (saveRazorpayConfig(razorpayConfig)) {
                toast.success('Razorpay preferences saved')
              } else {
                toast.error('Failed to save settings')
              }
            }}
            className="px-6 py-2.5 bg-purple-600 text-white rounded-lg font-medium text-sm hover:bg-purple-700 transition-colors"
          >
            Save Preferences
          </button>
        </div>
      </div>
    </motion.div>
  )
}

